module top_module(
    input reset,
    input clock,
    input ee,
    input ep,
    input hold,
    output veto
    );parameter NORMAL=2'b00;
parameter HOLDING=2'b01;
parameter ONLY_EE=2'b10;

reg [1:0] alt_state;

assign veto = (alt_state == ONLY_EE) & (~ee);

always @(posedge clock)
begin
	if(reset)
	begin
		alt_state <= NORMAL;
	end else begin
		case(alt_state)
			NORMAL:  if(hold) alt_state <= HOLDING;
						else alt_state <= NORMAL;

			HOLDING: if(hold)
							if(ep) alt_state <= ONLY_EE;
							else alt_state <= HOLDING;
						else
							alt_state <= NORMAL;

			ONLY_EE: if(hold) alt_state <= ONLY_EE;
						else if (ee)
							alt_state <= NORMAL;
						else alt_state <= ONLY_EE;
		endcase
	end
end

endmodule
